func Dispatch(name string, ctx context.Context, args map[string]interface{}) (ToolResponse, error) {
	h, ok := dispatchMap[name]
	if !ok {
		return ToolResponse{}, fmt.Errorf("unknown handler: %s", name)
	}
	return h(ctx, args)



}
